# Templates use {variable_name} placeholders filled by
# deal_context.get_variable_values() so every proposed
# replacement clause is calibrated to the specific deal.
#
# Variables injected at render time:
#   {liability_cap_months}      e.g. "12", "18", "24"
#   {liability_cap_amount}      e.g. "CAD $250,000"
#   {annual_fees}               e.g. "CAD $120,000"
#   {contract_value}            e.g. "CAD $500,000"
#   {notice_days}               e.g. "30", "60"
#   {cure_period_days}          e.g. "15"
#   {non_compete_months}        e.g. "12"
#   {non_solicitation_months}   e.g. "12"
#   {payment_days}              e.g. "30"
#   {late_fee_pct}              e.g. "1.5"
#   {confidentiality_years}     e.g. "3", "5"
#   {renewal_notice_days}       e.g. "60"
#   {initial_term}              e.g. "one (1) year"
#   {cgl_amount}                e.g. "2,000,000"
