def get_precedent(clause_category: str, contract_type: str) -> str:
    """Return the raw (unrendered) precedent template for a category and contract type."""
    category = PRECEDENT_CLAUSES.get(clause_category, {})
    return (category.get(contract_type)
            or category.get("default")
            or "")


def render_precedent(clause_category: str, contract_type: str, variables: dict) -> str:
    """
    Return the precedent clause with all {variable_name} placeholders filled
    from the provided variables dict (from deal_context.get_variable_values()).
    Falls back gracefully if a variable is missing.
    """
    template = get_precedent(clause_category, contract_type)
    if not template:
        return ""
    # Add computed variables
    extended = dict(variables)
    try:
        late_fee = float(variables.get("late_fee_pct", "1.5"))
        extended["late_fee_pct_x12"] = f"{late_fee * 12:.1f}"
    except (ValueError, TypeError):
        extended["late_fee_pct_x12"] = "18.0"
    # Fill placeholders, leave unfilled ones as-is for transparency
    import re
    def replacer(m):
        key = m.group(1)
        return extended.get(key, m.group(0))  # keep original if not found
    return re.sub(r'\{(\w+)\}', replacer, template)


def _truncate_at_sentence(text: str, max_chars: int = 800) -> str:
    """Truncate at a sentence boundary rather than mid-word or mid-clause.

    A hard character cut at 700 chars can produce legally misleading text by
    cutting mid-sentence (e.g. "liability shall not exceed..." with the cap
    amount on the next line). This function finds the last complete sentence
    within the limit before truncating.
    """
    if len(text) <= max_chars:
        return text
    window = text[:max_chars]
    # Look for the last sentence-ending punctuation followed by whitespace
    for delimiter in ('. ', '.\n', '; ', ';\n', ') ', ')\n'):
        idx = window.rfind(delimiter)
        if idx > max_chars * 0.5:  # Only accept if we keep at least half
            return window[:idx + len(delimiter)].rstrip() + " [...]"
    # Fallback: break at last space to avoid mid-word cut
    idx = window.rfind(' ')
    return (window[:idx] if idx > 0 else window) + " [...]"


def format_precedents_for_prompt(contract_type: str, variables: dict = None) -> str:
    """
    Format all relevant precedent clauses for injection into the system prompt.
    If variables are provided, renders templates; otherwise shows raw templates.
    """
    lines = [
        "The following vetted Canadian precedent clauses are available.",
        "Where you propose a replacement clause, ADAPT the most relevant precedent below",
        "rather than drafting from scratch. Fill in any remaining [bracketed] values",
        "from the contract context or deal context provided.\n"
    ]
    for cat_key, variants in PRECEDENT_CLAUSES.items():
        raw = variants.get(contract_type) or variants.get("default") or ""
        if not raw:
            continue
        label = cat_key.replace("_", " ").title()
        if variables:
            rendered = render_precedent(cat_key, contract_type, variables)
            clause_text = rendered
        else:
            clause_text = raw
        # Truncate for prompt — show enough to be useful
        truncated = _truncate_at_sentence(clause_text, max_chars=800)
        lines.append(f"--- {label} ---")
        lines.append(truncated)
        lines.append("")
    return "\n".join(lines)
